+    #[allow(clippy::too_many_arguments)]
+    fn render_idle_metaballs(
+        &mut self,
+        quality: FxQuality,
+        width: u16,
+        height: u16,
+        animation_seconds: f64,
+        theme_inputs: &ThemeInputs,
